static constexpr uint32_t UB_BUDGET_BYTES = 192 * 1024;
static constexpr uint32_t ALIGN_ELEMS = 128;

static inline uint32_t AlignDown(uint32_t x, uint32_t a) { return (x / a) * a; }
static inline uint32_t CeilDiv(uint32_t a, uint32_t b) { return (a + b - 1u) / b; }

static ge::graphStatus TilingFunc(gert::TilingContext *context)
{
    MaxPooling1dCustomTilingData tiling;

    auto inputShape = context->GetInputShape(0)->GetOriginShape();
    uint32_t batch = inputShape.GetDim(0);
    uint32_t features = inputShape.GetDim(1);
    uint32_t seqLen = inputShape.GetDim(2);

    const gert::RuntimeAttrs *attrs = context->GetAttrs();
    int64_t kernelSize = attrs->GetAttrPointer<int64_t>(0)[0];
    int64_t stride = attrs->GetAttrPointer<int64_t>(1)[0];
    int64_t padding = attrs->GetAttrPointer<int64_t>(2)[0];
    // return_indices attr is not used in tiling

    int32_t paddedLen = seqLen + 2 * padding;
    int32_t outLen = (paddedLen - kernelSize) / stride + 1;
    if (outLen < 0) outLen = 0;

    uint32_t totalSeqs = batch * features;
    uint32_t tileSeqs = 1;
    uint32_t blockDim = 8;

    context->SetBlockDim(blockDim);

    tiling.set_totalSeqs(totalSeqs);
    tiling.set_seqLen(seqLen);
    tiling.set_outLen(static_cast<uint32_t>(outLen));
    tiling.set_tileSeqs(tileSeqs);
    tiling.set_blockDim(blockDim);
    tiling.set_kernelSize(static_cast<int32_t>(kernelSize));
    tiling.set_stride(static_cast<int32_t>(stride));
    tiling.set_padding(static_cast<int32_t>(padding));

    tiling.SaveToBuffer(context->GetRawTilingData()->GetData(),
                        context->GetRawTilingData()->GetCapacity());
    context->GetRawTilingData()->SetDataSize(tiling.GetDataSize());

    size_t *currentWorkspace = context->GetWorkspaceSizes(1);
    currentWorkspace[0] = 0;
    return ge::GRAPH_SUCCESS;
}

} // namespace optiling

